#include <bits/stdc++.h>
using namespace std;
int main(){
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n, q; cin >> n >> q;
    vector<int> par(n + 1), sz(n + 1, 1);
    iota(par.begin(), par.end(), 0);
    function<int(int)> find = [&](int x){ return par[x] == x ? x : par[x] = find(par[x]); };
    while (q--){
        int op; cin >> op;
        if (op == 1) {
            int u, v; cin >> u >> v;
            int a = find(u), b = find(v);
            if (a == b) continue;
            if (sz[a] < sz[b]) swap(a, b);
            par[b] = a; sz[a] += sz[b];
        } else {
            int u; cin >> u;
            cout << sz[find(u)] << '\n';
        }
    }
}
